Node processAssignment(Assignment assignmentNode) {
      int type = transformTokenType(assignmentNode.getType());
      Node left = transform(assignmentNode.getLeft());
      Node right = transform(assignmentNode.getRight());
      Node assign = newNode(type, left, right);
      return assign;
    }

Node processUnaryExpression(UnaryExpression exprNode) {
      int type = transformTokenType(exprNode.getType());
      Node operand = transform(exprNode.getOperand());
      if (type == Token.NEG && operand.getType() == Token.NUMBER) {
        // Do not mutate the existing operand node; create a new number node.
        Node negNumber = Node.newNumber(-operand.getDouble());
        negNumber.copyInformationFrom(operand);
        return negNumber;
      } else {

        Node node = newNode(type, operand);
        if (exprNode.isPostfix()) {
          node.putBooleanProp(Node.INCRDECR_PROP, true);
        }
        return node;
      }
    }
